import{_ as a,o as t,c as i,an as n}from"./chunks/framework.CrWCHAFi.js";const u=JSON.parse('{"title":"Infrastructure and template sync","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/infrastructure.md","filePath":"getting-started/infrastructure.md","lastUpdated":null}'),s={name:"getting-started/infrastructure.md"};function r(o,e,d,l,p,c){return t(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="infrastructure" tabindex="-1">Infrastructure and template sync <a class="header-anchor" href="#infrastructure" aria-label="Permalink to &quot;Infrastructure and template sync {#infrastructure}&quot;">​</a></h1><p><code>ModifiedDistributions</code> adopts shared configuration and test infrastructure from <a href="https://github.com/EpiAware/EpiAwarePackageTools.jl" target="_blank" rel="noreferrer">EpiAwarePackageTools</a> (the kit). The kit owns the standard CI workflows, the documentation build, the quality and AD test harnesses, and the developer config. This page explains how that infrastructure is set up and how it stays current.</p><h2 id="Managed-and-package-owned-files" tabindex="-1">Managed and package-owned files <a class="header-anchor" href="#Managed-and-package-owned-files" aria-label="Permalink to &quot;Managed and package-owned files {#Managed-and-package-owned-files}&quot;">​</a></h2><p>Files fall into two classes.</p><ul><li><p>Managed files are the standard infrastructure (CI callers, the docs build, formatter and pre-commit config, coverage config). The kit rewrites them on every sync, so drift is removed automatically. Each managed file carries a <code>MANAGED by EpiAwarePackageTools.scaffold</code> header; do not edit them by hand.</p></li><li><p>Package-owned files are written once and never overwritten (unit tests, the QA config values, the navigation tree, the README body, <code>LICENSE</code>). These are yours to edit.</p></li></ul><h2 id="Staying-in-sync" tabindex="-1">Staying in sync <a class="header-anchor" href="#Staying-in-sync" aria-label="Permalink to &quot;Staying in sync {#Staying-in-sync}&quot;">​</a></h2><p>Two pieces keep <code>ModifiedDistributions</code> aligned with the kit.</p><ul><li><p>A scheduled template-sync workflow (<code>.github/workflows/template-sync.yaml</code>) re-runs the kit&#39;s <code>update</code> against this repository, then opens or refreshes a pull request when the committed infrastructure has drifted from the current standard.</p></li><li><p>Dependabot (<code>.github/dependabot.yml</code>) keeps the pinned reusable-workflow and action references current, so security and bug fixes in the shared workflows reach this repository without manual edits.</p></li></ul><p>Together they mean an improvement made once in the kit propagates to every adopting package.</p><h2 id="Adopting-or-updating-by-hand" tabindex="-1">Adopting or updating by hand <a class="header-anchor" href="#Adopting-or-updating-by-hand" aria-label="Permalink to &quot;Adopting or updating by hand {#Adopting-or-updating-by-hand}&quot;">​</a></h2><p>You can also run the kit directly from a Julia session:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EpiAwarePackageTools</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Re-apply the managed standard files and report drift.</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path/to/ModifiedDistributions.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p><code>update</code> rewrites only the managed files and reports which were changed; package-owned files are left untouched. See the <a href="https://github.com/EpiAware/EpiAwarePackageTools.jl" target="_blank" rel="noreferrer">EpiAwarePackageTools documentation</a> for the full set of options.</p>`,13)])])}const g=a(s,[["render",r]]);export{u as __pageData,g as default};
